import React, { useState } from 'react';

const API = 'http://192.168.0.100:5001';

const inp = { width:'100%', padding:'10px 14px', background:'#12121a', border:'1px solid #2d2d3f', borderRadius:10, color:'#e2e8f0', fontSize:14, marginBottom:12, outline:'none', boxSizing:'border-box' };
const btn = (color) => ({ width:'100%', padding:'11px', background:color||'linear-gradient(90deg,#6366f1,#8b5cf6)', border:'none', borderRadius:10, color:'#fff', fontWeight:600, fontSize:14, cursor:'pointer', marginTop:4 });

export default function Settings({ currentUser, token, onUpdate, onClose }) {
  const [username, setUsername] = useState(currentUser.username);
  const [password, setPassword] = useState('');
  const [showLastSeen, setShowLastSeen] = useState(currentUser.privacy?.showLastSeen ?? true);
  const [msg, setMsg] = useState('');
  const [loading, setLoading] = useState(false);

  const save = async () => {
    setLoading(true); setMsg('');
    const body = {};
    if (username !== currentUser.username) body.username = username;
    if (password) body.password = password;
    body.showLastSeen = showLastSeen;
    const res = await fetch(API + '/settings', {
      method: 'PUT',
      headers: { 'Content-Type': 'application/json', Authorization: `Bearer ${token}` },
      body: JSON.stringify(body)
    });
    const data = await res.json();
    setLoading(false);
    if (!res.ok) { setMsg('❌ ' + (data.error || 'Failed')); return; }
    setMsg('✅ Saved!');
    setPassword('');
    onUpdate(data.user, data.token);
  };

  const uploadPic = async (e) => {
    const file = e.target.files[0];
    if (!file) return;
    const fd = new FormData();
    fd.append('photo', file);
    const res = await fetch(API + '/settings/profile-pic', {
      method: 'POST',
      headers: { Authorization: `Bearer ${token}` },
      body: fd
    });
    const data = await res.json();
    if (data.profilePic) { setMsg('✅ Profile pic updated!'); onUpdate({ ...currentUser, profilePic: data.profilePic }, token); }
  };

  return (
    <div style={{ position:'fixed', inset:0, background:'rgba(0,0,0,0.7)', display:'flex', alignItems:'center', justifyContent:'center', zIndex:1000 }}>
      <div style={{ background:'#1e1e2e', border:'1px solid #2d2d3f', borderRadius:16, padding:'32px 24px', width:'90%', maxWidth:400, boxShadow:'0 24px 64px rgba(0,0,0,.6)', maxHeight:'90vh', overflowY:'auto' }}>
        <div style={{ display:'flex', justifyContent:'space-between', alignItems:'center', marginBottom:24 }}>
          <div style={{ fontSize:18, fontWeight:700, color:'#e2e8f0' }}>⚙️ Settings</div>
          <button onClick={onClose} style={{ background:'none', border:'none', color:'#64748b', fontSize:20, cursor:'pointer' }}>✕</button>
        </div>

        {/* Profile Pic */}
        <div style={{ display:'flex', alignItems:'center', gap:14, marginBottom:20 }}>
          {currentUser.profilePic
            ? <img src={currentUser.profilePic} alt="pfp" style={{ width:60, height:60, borderRadius:'50%', objectFit:'cover' }} />
            : <div style={{ width:60, height:60, borderRadius:'50%', background:'linear-gradient(135deg,#6366f1,#8b5cf6)', display:'flex', alignItems:'center', justifyContent:'center', fontSize:22, fontWeight:700, color:'#fff' }}>{currentUser.username[0].toUpperCase()}</div>
          }
          <label style={{ padding:'8px 16px', background:'#2d2d3f', border:'1px solid #3d3d5f', borderRadius:8, color:'#a5b4fc', fontSize:13, cursor:'pointer', fontWeight:500 }}>
            📷 Change Photo
            <input type="file" accept="image/*" style={{ display:'none' }} onChange={uploadPic} />
          </label>
        </div>

        <input style={inp} placeholder="Username" value={username} onChange={e => setUsername(e.target.value)} />
        <input style={inp} type="password" placeholder="New Password (leave blank to keep)" value={password} onChange={e => setPassword(e.target.value)} />

        {/* Last Seen Toggle */}
        <div style={{ display:'flex', alignItems:'center', justifyContent:'space-between', padding:'12px 14px', background:'#12121a', border:'1px solid #2d2d3f', borderRadius:10, marginBottom:12 }}>
          <div>
            <div style={{ fontSize:14, color:'#e2e8f0', fontWeight:500 }}>Show Last Seen</div>
            <div style={{ fontSize:11, color:'#64748b' }}>Friends can see when you were last active</div>
          </div>
          <div onClick={() => setShowLastSeen(p => !p)} style={{ width:44, height:24, borderRadius:12, background:showLastSeen?'#6366f1':'#2d2d3f', cursor:'pointer', position:'relative', transition:'background .2s' }}>
            <div style={{ position:'absolute', top:3, left:showLastSeen?22:3, width:18, height:18, borderRadius:'50%', background:'#fff', transition:'left .2s' }} />
          </div>
        </div>

        {msg && <div style={{ fontSize:13, color: msg.startsWith('✅') ? '#4ade80' : '#f87171', marginBottom:10, textAlign:'center' }}>{msg}</div>}
        <button style={btn()} onClick={save} disabled={loading}>{loading ? 'Saving...' : 'Save Changes'}</button>
      </div>
    </div>
  );
}
